class Solution {
public:
    bool dequeueFromFront(vector<int>& Q, int target) {
        if (Q.empty()) return false;
        int i = 0;
        for (; i < Q.size(); i++) {
            if (Q[i] == target) {
                Q.erase(Q.begin(), Q.begin() + i);
                return true;
            }
        }
        return false;
    }
};

