class Solution:
    def dequeue_from_front(self, Q, target) -> bool:
        """
        :param Q: queue to dequeue from
        :param target: element to remove
        :return: whether removal was successful
        """
        if not Q:
            return False
        i = 0
        while i < len(Q) and Q[i] != target:
            i += 1
        if i == len(Q):
            return False
        Q[:] = Q[i + 1:] + [None] * i + [None] * (len(Q) - i - 1)
        return True

